import React, { useState } from 'react';

// --- SECTION 1: SMALL CHOPS CURATES (LUXURY EDITION) ---
const Menu = () => {
  const gold = '#D4AF37';
  const fancyFont = "'Playfair Display', 'Georgia', serif";

  const items = [
    { 
      name: "The Starter Pack", 
      price: "15,000", 
      desc: "7 Samosas, 7 Springrolls, 15 Puff-puff, 10 Mosa (or 5 Money Bags), 4 Grilled Chicken pieces.",
      img: "/images/starter.jpg" 
    },
    { 
      name: "The Signature Platter", 
      price: "25,000", 
      desc: "10 Samosas, 10 Springrolls, 25 Puff-puff, 20 Mosa (or 10 Money Bags), 8 Grilled Chicken pieces.",
      img: "/images/signature.jpg"
    },
    { 
      name: "The Owambe Special", 
      price: "150,000", 
      desc: "Full event catering for 50 people. The ultimate party selection for prestigious gatherings.",
      img: "/images/owambe.jpg"
    }
  ];

  return (
    <div style={{ backgroundColor: '#000', padding: '40px 20px' }}>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', gap: '30px', marginBottom: '40px' }}>
        {items.map((item) => (
          <div key={item.name} style={{ border: `1px solid ${gold}22`, padding: '20px', textAlign: 'center', borderRadius: '4px', backgroundColor: '#050505' }}>
            <img src={item.img} alt={item.name} style={{ width: '100%', height: '220px', objectFit: 'contain', backgroundColor: '#0a0a0a', marginBottom: '15px' }} />
            <h4 style={{ color: gold, fontFamily: fancyFont, fontSize: '1.5rem', marginBottom: '10px' }}>{item.name}</h4>
            <p style={{ color: '#888', fontSize: '0.85rem', margin: '15px 0', minHeight: '50px', lineHeight: '1.6' }}>{item.desc}</p>
            <div style={{ color: gold, fontWeight: 'bold', fontSize: '1.3rem' }}>₦{item.price}</div>
            <button style={{ marginTop: '20px', background: 'none', border: `1px solid ${gold}`, color: gold, padding: '10px 25px', cursor: 'pointer', fontSize: '0.75rem', letterSpacing: '2px' }}>ADD TO BOX</button>
          </div>
        ))}
      </div>

      {/* LUXURY NOTE */}
      <p style={{ textAlign: 'center', color: '#555', fontStyle: 'italic', fontSize: '0.9rem', marginBottom: '50px' }}>
        "have a larger crowd for your parties and events curate your own platter starting at 200,000."
      </p>

      {/* BESPOKE CATERING (CUSTOMIZED) */}
      <div style={{ padding: '60px 20px', textAlign: 'center', border: `1px solid ${gold}33`, backgroundColor: '#080808', borderRadius: '8px' }}>
        <h3 style={{ color: gold, fontFamily: fancyFont, fontSize: '2rem', marginBottom: '15px' }}>Bespoke Catering</h3>
        <p style={{ color: '#888', fontSize: '1rem', marginBottom: '10px' }}>Starts at ₦200,000</p>
        <p style={{ color: '#666', fontSize: '0.9rem', marginBottom: '30px', maxWidth: '500px', margin: '0 auto 30px' }}>
          Tailor-made culinary experiences designed specifically for your high-profile events.
        </p>
        <button style={{ backgroundColor: gold, color: '#000', border: 'none', padding: '15px 40px', fontWeight: 'bold', cursor: 'pointer', letterSpacing: '1px' }}>REQUEST A CONSULTATION</button>
      </div>
    </div>
  );
};

export default Menu;

// --- SECTION 2: THE OFFICE LUNCH EXPERIENCE ---
export const Lunch = () => {
  const gold = '#D4AF37';
  const successGreen = '#2ecc71'; 
  const fancyFont = "'Playfair Display', 'Georgia', serif";
  const [isClockedIn, setIsClockedIn] = useState(false);

  const timetable = [
    { day: "Monday", meal: "Smoky Jollof, Grilled Chicken & Salad", nutrients: "Complex Carbs + Lean Protein + Fiber" },
    { day: "Tuesday", meal: "Creamy Pasta, Sauteed Prawns & Garlic Bread", nutrients: "Sustained Energy + Omega-3s + Carbs" },
    { day: "Wednesday", meal: "Native Rice, Shredded Beef & Fried Plantain", nutrients: "Iron + Potassium + Essential Minerals" },
    { day: "Thursday", meal: "Stir-fry Noodles, Teriyaki Wings & Veggies", nutrients: "Vitamin B12 + Antioxidants + Protein" },
    { day: "Friday", meal: "Chef's Special Surprise (TGIF Menu)", nutrients: "Dopamine Boost + 100% Organic 😊" }
  ];

  return (
    <div style={{ color: '#fff', padding: '40px 20px', maxWidth: '900px', margin: '0 auto' }}>
      <section style={{ textAlign: 'center', marginBottom: '60px' }}>
        <h3 style={{ fontFamily: fancyFont, color: gold, fontSize: '2.5rem', fontStyle: 'italic' }}>Fueling Your Ambition</h3>
        <p style={{ color: '#888', maxWidth: '650px', margin: '20px auto', lineHeight: '1.8' }}>
          As an office worker, your brain consumes 20% of your energy. We provide the fuel to eliminate the 3 PM slump.
        </p>

        <div style={{ 
          backgroundColor: '#0A0A0A', 
          border: `1.5px solid ${isClockedIn ? successGreen : gold + '33'}`, 
          padding: '40px', borderRadius: '8px', transition: '0.5s ease'
        }}>
          <h4 style={{ color: isClockedIn ? successGreen : gold, marginBottom: '15px', fontSize: '1.4rem', fontFamily: fancyFont }}>
            {isClockedIn ? "Enjoy Your Meal, Champion! ✅" : "Good Morning, Champion. ✨"}
          </h4>
          <button 
            onClick={() => setIsClockedIn(true)}
            disabled={isClockedIn}
            style={{ 
              backgroundColor: isClockedIn ? successGreen : gold, 
              color: '#000', border: 'none', padding: '12px 40px', fontWeight: 'bold', cursor: isClockedIn ? 'default' : 'pointer'
            }}
          >
            {isClockedIn ? "CLOCKED IN" : "CLOCK IN FOR TODAY'S MEAL"}
          </button>
        </div>
      </section>

      <section style={{ marginBottom: '80px' }}>
        <h3 style={{ fontFamily: fancyFont, color: gold, textAlign: 'center', marginBottom: '40px' }}>The Weekly Timetable</h3>
        <div style={{ border: `1px solid ${gold}22`, borderRadius: '4px' }}>
          {timetable.map((item) => (
            <div key={item.day} style={{ padding: '25px', borderBottom: '1px solid #111', backgroundColor: '#050505' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ color: gold, fontWeight: 'bold' }}>{item.day}</span>
                <span style={{ color: '#fff' }}>{item.meal}</span>
              </div>
              <div style={{ fontSize: '0.75rem', color: '#555', fontStyle: 'italic', marginTop: '5px' }}>
                Nutrients: {item.nutrients}
              </div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};
